div.p:
c
if (rc == -1) {
// Parent page also overflowed!
// Recurse: split_internal(parent_page, ...)
btree_split_internal(tree, parent_page_id,
cell_buf, cell_size, promoted_key,
&parent_promoted_key, &parent_new_page_id);
// Insert parent's promoted key into grandparent
btree_insert_into_parent(tree,
parent_page_id,
parent_promoted_key,
parent_new_page_id,
grandparent_page_id);
}

c
// Walk pointer array, copy each cell
for (i = 0; i < cell_count; i++) {
ptr = get_cell_pointer(page, hdr_sz, i);
key = cell_read_key(page, ptr, type);
size = cell_compute_size(page, ptr, type);
entries[idx].key  = key;
entries[idx].data = malloc(size);
memcpy(entries[idx].data, page+ptr, size);
// Insert overflow cell at correct position
if (!inserted && overflow_key < key) {
entries[idx-1] = {overflow_key,
overflow_cell, overflow_sz};
inserted = true;
}
idx++;
}
if (!inserted)  // overflow is largest
entries[idx++] = {overflow_key, ...};

c
page_init(page, PAGE_TYPE_TABLE_LEAF);
for (i = 0; i < m; i++) {         // i = 0,1,2
page_insert_cell(page,
entries[i].data,
entries[i].size,
entries[i].key);
}
pool_mark_dirty(pool, page_id);
pool_unpin_page(pool, page_id, true);

c
*new_page_id = pool_new_page(pool);
new_page = pool_fetch_page(pool, *new_page_id);
page_init(new_page, PAGE_TYPE_TABLE_LEAF);
for (i = m; i < total; i++) {      // i = 3,4,5,6
page_insert_cell(new_page,
entries[i].data,
entries[i].size,
entries[i].key);
}
pool_unpin_page(pool, *new_page_id, true);

c
// Build internal cell:
//   [left_child_page (4 bytes BE)] [varint(separator_key)]
uint8_t cell_buf[32];
int cell_size = cell_serialize_table_internal(
cell_buf, 32,
left_page_id,     // left child = original page
promoted_key);    // separator = 30
// Insert into parent at sorted position
int rc = page_insert_cell(parent_page,
cell_buf, cell_size, promoted_key);
// Update parent's right_child if needed:
// If this is the rightmost insertion,
// set right_child = new_page_id
write_be32(parent_page + 8, right_page_id);

c
void btree_create_new_root(BTree *tree,
page_id_t left_page_id,
page_id_t right_page_id,
int64_t separator_key)
{
page_id_t new_root = pool_new_page(pool);
uint8_t *root = pool_fetch_page(pool, new_root);
page_init(root, PAGE_TYPE_TABLE_INTERNAL);
// Single internal cell: left_child=left, key=separator
uint8_t cell[32];
int sz = cell_serialize_table_internal(
cell, 32, left_page_id, separator_key);
page_insert_cell(root, cell, sz, separator_key);
// right_child = right_page_id
write_be32(root + 8, right_page_id);
pool_unpin_page(pool, new_root, true);
tree->root_page = new_root;  // UPDATE root!
}
